import json

# Access childrens books and reviews using the correct variable names
childrens_books = var_functions.query_db_64
reviews_2020 = var_functions.query_db_54

# Map book_id to title
book_id_to_title = {}
for book in childrens_books:
    book_id_to_title[book['book_id']] = book['title']

# Collect ratings for each children's book
book_ratings = {}
for review in reviews_2020:
    purchase_id = review['purchase_id']
    book_id = purchase_id.replace('purchaseid_', 'bookid_')

    if book_id in book_id_to_title:
        rating = float(review['rating'])
        book_ratings.setdefault(book_id, []).append(rating)

# Calculate averages and filter >= 4.5
result = []
for book_id, ratings in book_ratings.items():
    avg_rating = sum(ratings) / len(ratings)
    if avg_rating >= 4.5:
        result.append({
            'title': book_id_to_title[book_id],
            'average_rating': round(avg_rating, 2),
            'review_count': len(ratings)
        })

result.sort(key=lambda x: x['average_rating'], reverse=True)

print('__RESULT__:')
print(json.dumps(result))

